package be.schaubroeck.lpb.rkm.rekenmotor.service.web;

import be.schaubroeck.lpb.corehr.util.web.relatie.HrWeddeDTO;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.RegulAgenda;
import be.schaubroeck.lpb.tools.Werkgever;
import be.schaubroeck.lpb.tools.enumtypes.BronAgenda;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.jpa.lo.RegulAgendaPK;
import be.schaubroeck.lpb.tools.jpa.lo.RegulAgendaPO;
import be.schaubroeck.lpb.tools.service.PersoonService;
import org.joda.time.LocalDate;
import org.springframework.beans.factory.annotation.Autowired;

public class StandaardRegulAgendaWebService implements RegulAgendaWebService {
    @Autowired
    protected PersoonService persoonService;
    @Autowired
    protected RekenmotorWebService rekenmotorWebService;

    @Override
    public void createRegulAgenda(Werkgever werkgever, Integer personeelsNr, Integer opdrachtNummer, HrWeddeDTO wedde) {
        final LocalDate today = new LocalDate();
        if (wedde.getActualFrom().isAfter(today.dayOfMonth().withMaximumValue())) {
            return;
        }
        Persoon persoon = persoonService.getByPersoneelsNr(werkgever.getAdmin(), personeelsNr);
        RegulAgendaPK pk = createPK(persoon, opdrachtNummer, wedde);
        RegulAgenda regulagenda = rekenmotorWebService.getRegulAgenda(werkgever, pk);

        if (regulagenda != null) {
            rekenmotorWebService.createRegulAgenda(werkgever, regulagenda);
        } else {
            RegulAgenda newRegulagenda = new RegulAgendaPO();
            newRegulagenda.setId(pk);
            newRegulagenda.setWerkgever(werkgever);
            newRegulagenda.setBron(BronAgenda.CORE_HR);
            rekenmotorWebService.createRegulAgenda(werkgever, newRegulagenda);
        }
    }

    private RegulAgendaPK createPK(Persoon persoon, Integer opdrachtNummer, HrWeddeDTO wedde) {
        final LocalDate today = new LocalDate();
        final LocalDate actualTo = wedde.getActualTo();
        final LocalDate minDate = actualTo.isBefore(today) ? actualTo : today;

        RegulAgendaPK pk = new RegulAgendaPK();
        pk.setRegulStatus(Regulkode.HERREKENEN_NOODZAKELIJK.getCode());
        pk.setBeginDatum(wedde.getActualFrom());
        pk.setEindDatum(minDate.dayOfMonth().withMaximumValue());
        pk.setOpdrachtNummer(opdrachtNummer);
        pk.setPersoon(persoon);

        return pk;
    }
}
